use std::time::{Duration, Instant};

struct AttemptResult {
    error_code: u32,
    timestamp: Instant,
}

struct BackoffConfig {
    initial_interval: Duration,
    max_interval: Duration,
    multiplier: f64,
}

fn calculate_next_backoff(last_attempt: &AttemptResult, config: &BackoffConfig) -> Option<Instant> {
    let elapsed = last_attempt.timestamp.elapsed();

    let calculated_duration = (config.multiplier.powf((elapsed.as_secs() as f64 / 1.0).max(1.0))) * config.initial_interval.as_secs_f64();

    let next_backoff = Duration::from_secs_f64(calculated_duration);

    if next_backoff > config.max_interval {
        return None;
    }

    Some(last_attempt.timestamp + next_backoff)
}

use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Mutex;

struct TokenStore {
    tokens: Mutex<Vec<String>>,
    is_locked: AtomicBool,
}

impl TokenStore {
    fn new(initial_tokens: Vec<String>) -> Self {
        TokenStore {
            tokens: Mutex::new(initial_tokens),
            is_locked: AtomicBool::new(false),
        }
    }

    fn try_acquire_lock(&self) -> bool {
        if self.is_locked.compare_exchange(false, true, Ordering::SeqCst, Ordering::SeqCst).is_ok() {
            true
        } else {
            false
        }
    }

    fn release_lock(&self) {
        self.is_locked.store(false, Ordering::SeqCst);
    }

    fn update_token(&self, new_token: String) -> Result<(), &'static str> {
        if !self.try_acquire_lock() {
            return Err("Store is currently busy with another operation.");
        }

        match self.tokens.lock() {
            Ok(mut tokens) => {
                println!("Lock acquired successfully for writing.");
                if !tokens.is_empty() {
                    tokens.pop();
                }
                tokens.push(new_token);
                self.release_lock();
                Ok(())
            }
            Err(_) => {
                self.release_lock();
                Err("Failed to acquire inner mutex guard.")
            }
        }
    }

    fn read_tokens(&self) -> Result<Vec<String>, &'static str> {
        if !self.try_acquire_lock() {
            return Err("Store is currently busy with another operation.");
        }

        let tokens = match self.tokens.lock() {
            Ok(guard) => guard.clone(),
            Err(_) => {
                self.release_lock();
                return Err("Failed to acquire inner mutex guard for reading.");
            }
        };

        self.release_lock();
        Ok(tokens)
    }
}
